import { type, scope } from "arktype"

// 1. Morph type: parses a string to a number using the "=>" operator
export const StringToNumber = type("string", "=>", (s) => Number(s))

// 2. Recursive scope: JSON value types using scope({...}).export()
export const JsonTypes = scope({
	JsonValue: "JsonPrimitive | JsonObject | JsonArray",
	JsonPrimitive: "string | number | boolean | null",
	JsonObject: "{ [k: string]: JsonValue }",
	JsonArray: "JsonValue[]"
})

export const { JsonValue } = JsonTypes.export()

// 3. Discriminated union: shapes selected by a literal 'kind' tag
export const Shape = type({
	kind: "'circle'",
	radius: "number"
}).or({
	kind: "'rectangle'",
	width: "number",
	height: "number"
})

// 4. Literal-string union: fixed set of role names
export const Role = type("'admin' | 'editor' | 'viewer'")

import { defineConfig } from "vitest/config"

export default defineConfig({
	test: {
		globalSetup: ["./setupVitest.ts"]
	}
})

import { describe, it } from "vitest"
import { attest } from "@arktype/attest"
import { type } from "arktype"
import { StringToNumber, JsonValue, Shape, Role } from "../src/schemas.js"

describe("ArkType schemas", () => {
	// 1. Pure compile-time type-equality check using attest<T>(value) form
	it("Role infers the correct literal union type", () => {
		attest<"admin" | "editor" | "viewer">(Role.infer)
	})

	// 2. Type serialized string check using .type.toString.snap(...)
	it("StringToNumber morph outputs number type", () => {
		attest(StringToNumber.infer).type.toString.snap("number")
	})

	// 3. Runtime throws check on a failing ArkType assertion
	it("Role.assert throws for an invalid role string", () => {
		attest(() => Role.assert("superadmin" as any)).throws(/superadmin/)
	})

	// 4. throwsAndHasTypeError with @ts-expect-error
	it("invalid modulo expression throws and has type error", () => {
		// @ts-expect-error
		attest(() => type("number%0")).throwsAndHasTypeError(/% operator/)
	})

	// 5. completions with @ts-expect-error
	it("type keyword completions for partial strings", () => {
		// @ts-expect-error
		attest(() => type({ a: "a", b: "b" })).completions({
			a: ["any", "alpha", "alphanumeric"],
			b: ["bigint", "boolean"]
		})
	})

	// 6. Type serialized string check using .type.toString direct call
	it("Role type serializes to a union including admin", () => {
		attest(Role.infer).type.toString(/admin/)
	})

	// 7. Discriminated union type check
	it("Shape infers a discriminated union with kind", () => {
		attest(Shape.infer).type.toString(/kind/)
	})

	// 8. Recursive scope type check
	it("JsonValue is a recursive type referencing itself", () => {
		attest(JsonValue.infer).type.toString(/JsonValue/)
	})
})

